import postgres from 'postgres';

/**
 * Lấy đối tượng kết nối DB dựa vào biến môi trường.
 * Sử dụng thư viện 'postgres' thay cho Neon để tương thích với Supabase Transaction Pooler.
 */
export function getDb(env) {
    if (!env.DATABASE_URL) {
        throw new Error('DATABASE_URL is not defined in environment variables');
    }

    // Khởi tạo connection pool thông qua Postgres client
    // Set ssl: 'require' để đảm bảo kết nối qua SSL (bắt buộc cho Supabase Cloudflare)
    const sql = postgres(env.DATABASE_URL, {
        ssl: 'require',
        max: 5 // Giới hạn connection pool trên Serverless Function để tránh cạn kiệt (Limit pool)
    });

    return sql;
}
